"use strict";parserFactory.register("czbooks.net",()=>new CzbooksParser);class CzbooksParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=e.querySelector("ul.chapter-list");return util.hyperlinksToChapterList(t)}findContent(e){return e.querySelector(".content")}extractTitleImpl(e){return e.querySelector(".novel-detail .title")}extractAuthor(e){let t=e.querySelector(".novel-detail span.author a");return t?.textContent??super.extractAuthor(e)}findChapterTitle(e){return e.querySelector(".name")}findCoverImageUrl(e){return util.getFirstImgSrc(e,".novel-detail")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".description")]}}